class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_layers):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_layers = hidden_layers
        self.weights = []
        self.biases = []
        self.activations = []
        self.deltas = []
        self.outputs = []
        self.init_network()

    def init_network(self):
        layers = [self.input_dim] + self.hidden_layers + [self.output_dim]
        for i in range(len(layers) - 1):
            self.weights.append([[0.1 for _ in range(layers[i + 1])] for _ in range(layers[i])])
            self.biases.append([0.1 for _ in range(layers[i + 1])])
            self.activations.append([0 for _ in range(layers[i + 1])])
            self.deltas.append([0 for _ in range(layers[i + 1])])
            self.outputs.append([0 for _ in range(layers[i + 1])])

    def sigmoid(self, x):
        return 1 / (1 + 2.71828 ** -x)

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def forward_pass(self, inputs):
        self.outputs[0] = inputs
        for i in range(len(self.weights)):
            for j in range(len(self.weights[i][0])):
                sum = 0
                for k in range(len(self.weights[i])):
                    sum += self.outputs[i][k] * self.weights[i][k][j]
                sum += self.biases[i][j]
                self.activations[i + 1][j] = self.sigmoid(sum)
            self.outputs[i + 1] = self.activations[i + 1]

    def backward_pass(self, targets):
        for i in range(len(self.weights) - 1, -1, -1):
            for j in range(len(self.weights[i][0])):
                if i == len(self.weights) - 1:
                    self.deltas[i][j] = (targets[j] - self.outputs[i + 1][j]) * self.sigmoid_derivative(self.outputs[i + 1][j])
                else:
                    sum = 0
                    for k in range(len(self.weights[i + 1][0])):
                        sum += self.deltas[i + 1][k] * self.weights[i + 1][j][k]
                    self.deltas[i][j] = sum * self.sigmoid_derivative(self.outputs[i + 1][j])
            for j in range(len(self.weights[i])):
                for k in range(len(self.weights[i][0])):
                    self.weights[i][j][k] += 0.1 * self.deltas[i][k] * self.outputs[i][j]

    def train(self, inputs, targets):
        self.forward_pass(inputs)
        self.backward_pass(targets)

    def predict(self, inputs):
        self.forward_pass(inputs)
        return self.outputs[-1]

