class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layers):
        self.input_size = input_size
        self.output_size = output_size
        self.hidden_layers = hidden_layers
        self.weights = []
        self.biases = []
        self.activations = []
        self.deltas = []
        self.outputs = []
        self.initialize_network()

    def initialize_network(self):
        num_layers = len(self.hidden_layers) + 2
        for i in range(num_layers - 1):
            if i == 0:
                self.weights.append(self.initialize_weight(self.input_size, self.hidden_layers[i]))
                self.biases.append(self.initialize_bias(self.hidden_layers[i]))
            elif i == num_layers - 2:
                self.weights.append(self.initialize_weight(self.hidden_layers[i-1], self.output_size))
                self.biases.append(self.initialize_bias(self.output_size))
            else:
                self.weights.append(self.initialize_weight(self.hidden_layers[i-1], self.hidden_layers[i]))
                self.biases.append(self.initialize_bias(self.hidden_layers[i]))
            self.activations.append(self.relu)
            self.deltas.append([0 for _ in range(self.hidden_layers[i] if i < num_layers - 2 else self.output_size)])
            self.outputs.append([0 for _ in range(self.hidden_layers[i] if i < num_layers - 2 else self.output_size)])

    def initialize_weight(self, input_size, output_size):
        return [[0.1 for _ in range(output_size)] for _ in range(input_size)]

    def initialize_bias(self, size):
        return [0.1 for _ in range(size)]

    def relu(self, x):
        return max(0, x)

    def sigmoid(self, x):
        return 1 / (1 + 2.71828 ** -x)

    def forward_pass(self, inputs):
        self.outputs[0] = [self.sigmoid(sum([inputs[i] * self.weights[0][i][j] for i in range(self.input_size)]) + self.biases[0][j]) for j in range(self.hidden_layers[0])]
        for i in range(1, len(self.hidden_layers)):
            self.outputs[i] = [self.sigmoid(sum([self.outputs[i-1][k] * self.weights[i][k][j] for k in range(self.hidden_layers[i-1])]) + self.biases[i][j]) for j in range(self.hidden_layers[i])]
        self.outputs[-1] = [self.sigmoid(sum([self.outputs[-2][i] * self.weights[-1][i][j] for i in range(self.hidden_layers[-1])]) + self.biases[-1][j]) for j in range(self.output_size)]
        return self.outputs[-1]

    def backward_pass(self, targets, learning_rate):
        output_error = [targets[i] - self.outputs[-1][i] for i in range(self.output_size)]
        self.deltas[-1] = [output_error[i] * self.outputs[-1][i] * (1 - self.outputs[-1][i]) for i in range(self.output_size)]
        for i in range(len(self.hidden_layers) - 1, -1, -1):
            if i == len(self.hidden_layers) - 1:
                self.deltas[i] = [sum([self.deltas[-1][k] * self.weights[-1][i][k] for k in range(self.output_size)]) * self.outputs[i][j] * (1 - self.outputs[i][j]) for j in range(self.hidden_layers[i])]
            else:
                self.deltas[i] = [sum([self.deltas[i+1][k] * self.weights[i+1][j][k] for k in range(self.hidden_layers[i+1])]) * self.outputs[i][j] * (1 - self.outputs[i][j]) for j in range(self.hidden_layers[i])]
        for i in range(len(self.weights)):
            if i == len(self.weights) - 1:
                for j in range(self.hidden_layers[-1]):
                    for k in range(self.output_size):
                        self.weights[-1][j][k] += learning_rate * self.deltas[-1][k] * self.outputs[-2][j]
            else:
                for j in range(self.hidden_layers[i-1] if i > 0 else self.input_size):
                    for k in range(self.hidden_layers[i]):
                        self.weights[i][j][k] += learning_rate * self.deltas[i][k] * (self.outputs[i-1][j] if i > 0 else inputs[j])
        for i in range(len(self.biases)):
            for j in range(len(self.biases[i])):
                self.biases[i][j] += learning_rate * self.deltas[i][j]

    def train(self, inputs, targets, learning_rate):
        self.forward_pass(inputs)
        self.backward_pass(targets, learning_rate)

