class Neuron:
    def __init__(self, inputs):
        self.inputs = inputs
        self.weights = [0.0 for _ in range(inputs)]
        self.bias = 0.0
        self.output = 0.0
        self.delta = 0.0

    def sigmoid(self, x):
        return 1 / (1 + 2.71828 ** -x)

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def calculate_output(self, inputs):
        weighted_sum = sum([inputs[i] * self.weights[i] for i in range(self.inputs)]) + self.bias
        self.output = self.sigmoid(weighted_sum)
        return self.output

    def calculate_delta(self, error):
        self.delta = error * self.sigmoid_derivative(self.output)


class Layer:
    def __init__(self, neurons, inputs):
        self.neurons = [Neuron(inputs) for _ in range(neurons)]

    def calculate_outputs(self, inputs):
        return [neuron.calculate_output(inputs) for neuron in self.neurons]

    def calculate_deltas(self, errors):
        for i in range(len(self.neurons)):
            self.neurons[i].calculate_delta(errors[i])


class NeuralNetwork:
    def __init__(self, inputs, hidden, outputs):
        self.layers = []
        self.layers.append(Layer(hidden[0], inputs))
        for i in range(1, len(hidden)):
            self.layers.append(Layer(hidden[i], hidden[i - 1]))
        self.layers.append(Layer(outputs, hidden[-1]))

    def calculate_outputs(self, inputs):
        outputs = inputs
        for layer in self.layers:
            outputs = layer.calculate_outputs(outputs)
        return outputs

    def calculate_deltas(self, targets):
        errors = [target - output for target, output in zip(targets, self.layers[-1].calculate_outputs([0.0 for _ in range(self.layers[-1].neurons[0].inputs)]))]
        for i in range(len(self.layers) - 1, -1, -1):
            if i == len(self.layers) - 1:
                self.layers[i].calculate_deltas(errors)
            else:
                errors = [sum([self.layers[i + 1].neurons[j].weights[k] * self.layers[i + 1].neurons[j].delta for j in range(len(self.layers[i + 1].neurons))]) for k in range(len(self.layers[i].neurons[0].weights))]
                self.layers[i].calculate_deltas(errors)

    def update_weights(self, inputs, learning_rate):
        outputs = inputs
        for i in range(len(self.layers)):
            if i == 0:
                for j in range(len(self.layers[i].neurons)):
                    for k in range(len(self.layers[i].neurons[j].weights)):
                        self.layers[i].neurons[j].weights[k] += learning_rate * self.layers[i].neurons[j].delta * outputs[k]
                    self.layers[i].neurons[j].bias += learning_rate * self.layers[i].neurons[j].delta
            else:
                for j in range(len(self.layers[i].neurons)):
                    for k in range(len(self.layers[i].neurons[j].weights)):
                        self.layers[i].neurons[j].weights[k] += learning_rate * self.layers[i].neurons[j].delta * outputs[k]
                    self.layers[i].neurons[j].bias += learning_rate * self.layers[i].neurons[j].delta
            outputs = self.layers[i].calculate_outputs(outputs)

    def train(self, inputs, targets, learning_rate, iterations):
        for _ in range(iterations):
            self.calculate_outputs(inputs)
            self.calculate_deltas(targets)
            self.update_weights(inputs, learning_rate)


