class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_layers):
        self.layers = []
        self.layers.append(Layer(input_dim, hidden_layers[0]))
        for i in range(len(hidden_layers) - 1):
            self.layers.append(Layer(hidden_layers[i], hidden_layers[i+1]))
        self.layers.append(Layer(hidden_layers[-1], output_dim))
        self.activations = [Activation('relu') for _ in range(len(hidden_layers))]
        self.activations.append(Activation('sigmoid'))

    def forward(self, x):
        outputs = []
        for i in range(len(self.layers)):
            if i == 0:
                output = self.layers[i].forward(x)
            else:
                output = self.layers[i].forward(outputs[-1])
            if i < len(self.layers) - 1:
                output = self.activations[i].forward(output)
            outputs.append(output)
        return outputs

    def backward(self, x, y, learning_rate):
        outputs = self.forward(x)
        error = y - outputs[-1]
        for i in range(len(self.layers) - 1, -1, -1):
            if i == len(self.layers) - 1:
                delta = error
            else:
                delta = np.dot(delta, self.layers[i+1].weights.T)
            if i < len(self.layers) - 1:
                delta *= self.activations[i].forward(outputs[i]) * (1 - self.activations[i].forward(outputs[i]))
            self.layers[i].weights += learning_rate * np.dot(outputs[i-1].T if i > 0 else x.T, delta)
            self.layers[i].bias += learning_rate * np.sum(delta, axis=0, keepdims=True)

    def train(self, x, y, learning_rate, epochs):
        for _ in range(epochs):
            self.backward(x, y, learning_rate)

