import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_dims, activations):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_dims = hidden_dims
        self.activations = activations
        self.weights = []
        self.biases = []
        self.initialize_weights_and_biases()

    def initialize_weights_and_biases(self):
        dims = [self.input_dim] + self.hidden_dims + [self.output_dim]
        for i in range(len(dims) - 1):
            self.weights.append(np.random.rand(dims[i], dims[i + 1]))
            self.biases.append(np.zeros((1, dims[i + 1])))

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return np.maximum(x, 0)

    def relu_derivative(self, x):
        return (x > 0).astype(int)

    def tanh(self, x):
        return np.tanh(x)

    def tanh_derivative(self, x):
        return 1 - x ** 2

    def softmax(self, x):
        e_x = np.exp(x - np.max(x))
        return e_x / e_x.sum(axis=1, keepdims=True)

    def forward_pass(self, inputs):
        activations = [inputs]
        for i in range(len(self.weights)):
            linear_output = np.dot(activations[-1], self.weights[i]) + self.biases[i]
            if self.activations[i] == 'sigmoid':
                activation = self.sigmoid(linear_output)
            elif self.activations[i] == 'relu':
                activation = self.relu(linear_output)
            elif self.activations[i] == 'tanh':
                activation = self.tanh(linear_output)
            else:
                raise ValueError('Invalid activation function')
            activations.append(activation)
        if self.activations[-1] == 'softmax':
            activations[-1] = self.softmax(activations[-1])
        return activations

    def backward_pass(self, inputs, targets, learning_rate):
        activations = self.forward_pass(inputs)
        error = targets - activations[-1]
        for i in range(len(self.weights) - 1, -1, -1):
            if self.activations[i] == 'sigmoid':
                delta = error * self.sigmoid_derivative(activations[i + 1])
            elif self.activations[i] == 'relu':
                delta = error * self.relu_derivative(activations[i + 1])
            elif self.activations[i] == 'tanh':
                delta = error * self.tanh_derivative(activations[i + 1])
            else:
                raise ValueError('Invalid activation function')
            if i == len(self.weights) - 1:
                delta = delta
            else:
                delta = np.dot(delta, self.weights[i + 1].T)
            self.weights[i] += learning_rate * np.dot(activations[i].T, delta)
            self.biases[i] += learning_rate * np.sum(delta, axis=0, keepdims=True)
            error = delta
        return np.mean(np.square(error))

    def train(self, inputs, targets, learning_rate, num_iterations):
        for _ in range(num_iterations):
            self.backward_pass(inputs, targets, learning_rate)

    def predict(self, inputs):
        return self.forward_pass(inputs)[-1]

