        self.outputs[0] = inputs
        for i in range(len(self.weights)):
            weighted_sum = [sum([self.weights[i][j][k] * self.outputs[i][k] for k in range(len(self.outputs[i]))]) + self.biases[i][j] for j in range(len(self.weights[i]))]
            if i < len(self.weights) - 1:
                self.activations[i] = [self.relu(x) for x in weighted_sum]
            else:
                self.activations[i] = [self.sigmoid(x) for x in weighted_sum]
            self.outputs[i + 1] = self.activations[i]
        return self.outputs[-1]

    def backward_pass(self, targets, learning_rate):
        self.deltas[-1] = [(targets[i] - self.outputs[-1][i]) * self.sigmoid_derivative(self.outputs[-1][i]) for i in range(len(targets))]
        for i in range(len(self.weights) - 2, -1, -1):
            self.deltas[i] = [sum([self.deltas[i + 1][j] * self.weights[i + 1][j][k] for j in range(len(self.deltas[i + 1]))]) * self.relu_derivative(self.activations[i][k]) for k in range(len(self.activations[i]))]
        for i in range(len(self.weights)):
            for j in range(len(self.weights[i])):
                for k in range(len(self.weights[i][j])):
                    self.weights[i][j][k] += learning_rate * self.deltas[i][j] * self.outputs[i][k]
                self.biases[i][j] += learning_rate * self.deltas[i][j]

    def train(self, inputs, targets, learning_rate, epochs):
        for _ in range(epochs):
            self.forward_pass(inputs)
            self.backward_pass(targets, learning_rate)

    def predict(self, inputs):
        return self.forward_pass(inputs)


