import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_layers):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_layers = hidden_layers
        self.weights = []
        self.biases = []
        self.activations = []

        # Initialize weights and biases
        self.weights.append(np.random.rand(self.input_dim, self.hidden_layers[0]))
        self.biases.append(np.zeros((1, self.hidden_layers[0])))
        self.activations.append('relu')

        for i in range(1, len(self.hidden_layers)):
            self.weights.append(np.random.rand(self.hidden_layers[i-1], self.hidden_layers[i]))
            self.biases.append(np.zeros((1, self.hidden_layers[i])))
            self.activations.append('relu')

        self.weights.append(np.random.rand(self.hidden_layers[-1], self.output_dim))
        self.biases.append(np.zeros((1, self.output_dim)))
        self.activations.append('sigmoid' if output_dim == 1 else 'softmax')

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def relu(self, x):
        return np.maximum(x, 0)

    def softmax(self, x):
        return np.exp(x) / np.sum(np.exp(x), axis=1, keepdims=True)

    def activation(self, x, activation):
        if activation == 'sigmoid':
            return self.sigmoid(x)
        elif activation == 'relu':
            return self.relu(x)
        elif activation == 'softmax':
            return self.softmax(x)

    def forward(self, x):
        outputs = []
        for i in range(len(self.weights)):
            x = np.dot(x, self.weights[i]) + self.biases[i]
            x = self.activation(x, self.activations[i])
            outputs.append(x)
        return outputs

    def backward(self, x, y, outputs, learning_rate):
        errors = []
        for i in range(len(self.weights) - 1, -1, -1):
            if i == len(self.weights) - 1:
                error = (outputs[-1] - y) * (outputs[-1] * (1 - outputs[-1]) if self.activations[-1] == 'sigmoid' else outputs[-1] - np.max(outputs[-1], axis=1, keepdims=True))
            else:
                error = np.dot(errors[-1], self.weights[i+1].T) * (outputs[i] * (1 - outputs[i]) if self.activations[i] == 'sigmoid' else np.where(outputs[i] > 0, 1, 0))
            errors.append(error)

        for i in range(len(self.weights)):
            self.weights[i] -= learning_rate * np.dot(outputs[i-1].T if i > 0 else x.T, errors[-i-1])
            self.biases[i] -= learning_rate * np.sum(errors[-i-1], axis=0, keepdims=True)

    def train(self, x, y, epochs, learning_rate):
        for epoch in range(epochs):
            outputs = self.forward(x)
            self.backward(x, y, outputs, learning_rate)
            print(f'Epoch {epoch+1}, Loss: {np.mean((outputs[-1] - y) ** 2)}')

    def predict(self, x):
        outputs = self.forward(x)
        return outputs[-1]

