import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, hidden_layers, output_dim):
        self.input_dim = input_dim
        self.hidden_layers = hidden_layers
        self.output_dim = output_dim
        self.weights = []
        self.biases = []
        self.init_weights_and_biases()

    def init_weights_and_biases(self):
        layers = [self.input_dim] + self.hidden_layers + [self.output_dim]
        for i in range(len(layers) - 1):
            weight = np.random.rand(layers[i], layers[i + 1])
            bias = np.zeros((1, layers[i + 1]))
            self.weights.append(weight)
            self.biases.append(bias)

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return np.maximum(x, 0)

    def relu_derivative(self, x):
        return np.where(x > 0, 1, 0)

    def forward(self, inputs):
        a = inputs
        activations = [inputs]
        for i in range(len(self.weights)):
            z = np.dot(a, self.weights[i]) + self.biases[i]
            if i < len(self.weights) - 1:
                a = self.relu(z)
            else:
                a = self.sigmoid(z)
            activations.append(a)
        return activations

    def backward(self, inputs, targets, learning_rate):
        activations = self.forward(inputs)
        errors = targets - activations[-1]
        d_weights = []
        d_biases = []
        for i in reversed(range(len(self.weights))):
            if i == len(self.weights) - 1:
                d_a = errors * self.sigmoid_derivative(activations[-1])
            else:
                d_a = np.dot(d_a, self.weights[i + 1].T) * self.relu_derivative(activations[i + 1])
            if i == 0:
                d_w = np.dot(inputs.T, d_a)
            else:
                d_w = np.dot(activations[i].T, d_a)
            d_b = np.sum(d_a, axis=0, keepdims=True)
            d_weights.append(d_w)
            d_biases.append(d_b)
        d_weights = list(reversed(d_weights))
        d_biases = list(reversed(d_biases))
        for i in range(len(self.weights)):
            self.weights[i] += learning_rate * d_weights[i]
            self.biases[i] += learning_rate * d_biases[i]

class Regression:
