        self.model = NeuralNetwork(input_dim, hidden_layers, output_dim)

    def train(self, inputs, targets, epochs, learning_rate):
        for epoch in range(epochs):
            self.model.backward(inputs, targets, learning_rate)
            predictions = self.model.forward(inputs)[-1]
            loss = np.mean(np.square(predictions - targets))
            print(f'Epoch {epoch+1}, Loss: {loss}')

    def predict(self, inputs):
        return self.model.forward(inputs)[-1]

