        output = self.forward(X)
        error = y - output
        for i in range(len(self.layers) - 1, -1, -1):
            layer = self.layers[i]
            if i == len(self.layers) - 1:
                layer.delta = error
            else:
                layer.delta = np.dot(self.layers[i + 1].delta, self.layers[i + 1].weights.T)
