            if i == 0:
                outputs.append(self.layers[i].forward(x))
            else:
                outputs.append(self.layers[i].forward(outputs[-1]))
            if i < len(self.layers) - 1:
                outputs[-1] = self.activations[i - 1].forward(outputs[-1])
        return outputs

    def backward(self, x, y, learning_rate):
        outputs = self.forward(x)
        loss = np.mean((outputs[-1] - y) ** 2)
        dy = 2 * (outputs[-1] - y)
