            dy = self.activations[i].backward(outputs[i], dy)
            dy = np.dot(dy, self.layers[i + 1].weights.T)
            dw, db = self.layers[i].backward(outputs[i - 1] if i > 0 else x, dy)
            self.layers[i].weights -= learning_rate * dw
            self.layers[i].bias -= learning_rate * db
        return loss

    def train(self, x, y, learning_rate, epochs):
        for _ in range(epochs):
            loss = self.backward(x, y, learning_rate)
