                self.weights.append(np.random.rand(input_dim, hidden_layers[i]))
                self.biases.append(np.zeros((1, hidden_layers[i])))
            elif i == len(hidden_layers):
                self.weights.append(np.random.rand(hidden_layers[i-1], output_dim))
                self.biases.append(np.zeros((1, output_dim)))
            else:
                self.weights.append(np.random.rand(hidden_layers[i-1], hidden_layers[i]))
                self.biases.append(np.zeros((1, hidden_layers[i])))

        self.activations = [self.sigmoid for _ in range(len(hidden_layers) + 1)]
        self.derivatives = [self.sigmoid_derivative for _ in range(len(hidden_layers) + 1)]

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

