        outputs = []
        for i in range(len(self.weights)):
            if i == 0:
                output = np.dot(inputs, self.weights[i]) + self.biases[i]
            else:
                output = np.dot(outputs[-1], self.weights[i]) + self.biases[i]
            output = self.activations[i](output)
            outputs.append(output)
        return outputs

    def backward_pass(self, inputs, targets, outputs):
        errors = []
        for i in range(len(self.weights) - 1, -1, -1):
            if i == len(self.weights) - 1:
                error = targets - outputs[-1]
            else:
                error = np.dot(errors[-1], self.weights[i+1].T)
            error *= self.derivatives[i](outputs[i])
            errors.append(error)
        errors.reverse()
        return errors

    def update_weights(self, inputs, errors, outputs):
        for i in range(len(self.weights)):
            if i == 0:
                self.weights[i] += np.dot(inputs.T, errors[i])
            else:
                self.weights[i] += np.dot(outputs[i-1].T, errors[i])
            self.biases[i] += np.sum(errors[i], axis=0, keepdims=True)

    def train(self, inputs, targets, epochs):
        for _ in range(epochs):
            outputs = self.forward_pass(inputs)
            errors = self.backward_pass(inputs, targets, outputs)
            self.update_weights(inputs, errors, outputs)

