        activations = [inputs]
        for i in range(len(self.weights)):
            weighted_sum = self.calculate_weighted_sum(activations[-1], self.weights[i], self.biases[i])
            if self.activation == 'sigmoid':
                activation = [self.sigmoid(x) for x in weighted_sum]
            elif self.activation == 'relu':
