        self.biases.append(np.zeros((1, output_dim)))
        self.activations.append(self.sigmoid if output_dim == 1 else self.softmax)

    def relu(self, x):
        return np.maximum(x, 0)

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def softmax(self, x):
        return np.exp(x) / np.sum(np.exp(x), axis=1, keepdims=True)

    def forward(self, x):
        outputs = []
        for i in range(len(self.weights)):
            x = np.dot(x, self.weights[i]) + self.biases[i]
            x = self.activations[i](x)
            outputs.append(x)
        return outputs

    def backward(self, inputs, targets, outputs, learning_rate):
        errors = [None] * len(self.weights)
        for i in range(len(self.weights)-1, -1, -1):
            if i == len(self.weights)-1:
                errors[i] = targets - outputs[i]
            else:
                errors[i] = np.dot(errors[i+1], self.weights[i+1].T) * self.d_relu(outputs[i]) if self.activations[i] == self.relu else np.dot(errors[i+1], self.weights[i+1].T) * self.d_sigmoid(outputs[i])
            self.weights[i] += learning_rate * np.dot(inputs[i].T, errors[i])
            self.biases[i] += learning_rate * np.sum(errors[i], axis=0, keepdims=True)
            inputs = outputs[i]

    def d_relu(self, x):
        return (x > 0).astype(int)

    def d_sigmoid(self, x):
        return x * (1 - x)

    def train(self, inputs, targets, epochs, learning_rate):
        for _ in range(epochs):
            outputs = self.forward(inputs)
            self.backward(inputs, targets, outputs, learning_rate)

    def predict(self, inputs):
        outputs = self.forward(inputs)
        return outputs[-1]

