    def relu(self, x):
        return max(0, x)

    def relu_derivative(self, x):
        return 1 if x > 0 else 0

    def forward_pass(self, inputs):
        outputs = inputs
        self.layer_outputs = [outputs]
        for i in range(len(self.weights)):
            weighted_sum = [sum(self.weights[i][j][k] * outputs[j] for j in range(len(outputs))) + self.biases[i][k] for k in range(len(self.biases[i]))]
            if i < len(self.weights) - 1:
