        for i in range(len(self.weights) - 1, -1, -1):
            weight_updates = [[0 for _ in range(len(self.weights[i][0]))] for _ in range(len(self.weights[i]))]
            bias_updates = [0 for _ in range(len(self.biases[i]))]
            for j in range(len(self.layer_outputs[i])):
                output = self.layer_outputs[i][j]
                if i < len(self.weights) - 1:
                    derivative = self.relu_derivative(output)
                else:
                    derivative = self.sigmoid_derivative(output)
                for k in range(len(self.weights[i][0])):
                    weight_updates[j][k] = error_gradients[k] * derivative * output
                    bias_updates[k] = error_gradients[k] * derivative
            for j in range(len(self.weights[i])):
