                    self.weights[i][j][k] -= 0.1 * weight_updates[j][k]
            for k in range(len(self.biases[i])):
                self.biases[i][k] -= 0.1 * bias_updates[k]
            error_gradients = [sum(self.weights[i][j][k] * error_gradients[k] for k in range(len(error_gradients))) * (self.relu_derivative(self.layer_outputs[i][j]) if i < len(self.weights) - 1 else self.sigmoid_derivative(self.layer_outputs[i][j])) for j in range(len(self.layer_outputs[i]))]

    def train(self, inputs, actuals, epochs):
        for _ in range(epochs):
            for inputs, actuals in zip(inputs, actuals):
                self.forward_pass(inputs)
                self.backpropagate(inputs, actuals)

