    def __init__(self, input_dim, hidden_dim, output_dim, num_hidden_layers):
        self.input_dim = input_dim
        self.hidden_dim = hidden_dim
        self.output_dim = output_dim
        self.num_hidden_layers = num_hidden_layers
        self.weights = []
        self.biases = []
        self.activations = []
        self.deltas = []
        self.outputs = []
        self.initialize_weights_and_biases()

    def initialize_weights_and_biases(self):
        for i in range(self.num_hidden_layers + 1):
            if i == 0:
                self.weights.append(self.initialize_weight(self.input_dim, self.hidden_dim))
                self.biases.append(self.initialize_bias(self.hidden_dim))
            elif i == self.num_hidden_layers:
                self.weights.append(self.initialize_weight(self.hidden_dim, self.output_dim))
                self.biases.append(self.initialize_bias(self.output_dim))
            else:
                self.weights.append(self.initialize_weight(self.hidden_dim, self.hidden_dim))
                self.biases.append(self.initialize_bias(self.hidden_dim))

    def initialize_weight(self, input_dim, output_dim):
        return [[0.1 for _ in range(output_dim)] for _ in range(input_dim)]

    def initialize_bias(self, output_dim):
        return [0.1 for _ in range(output_dim)]

    def sigmoid(self, x):
        return 1 / (1 + 2.71828 ** -x)

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return max(0, x)

    def relu_derivative(self, x):
        return 1 if x > 0 else 0

    def forward_propagate(self, inputs):
        self.outputs = [inputs]
        self.activations = []
        for i in range(self.num_hidden_layers + 1):
            if i == 0:
                weighted_sum = self.calculate_weighted_sum(inputs, self.weights[i], self.biases[i])
                activation = [self.sigmoid(x) for x in weighted_sum]
            else:
                weighted_sum = self.calculate_weighted_sum(self.activations[-1], self.weights[i], self.biases[i])
                if i == self.num_hidden_layers:
                    activation = [self.sigmoid(x) for x in weighted_sum]
                else:
                    activation = [self.relu(x) for x in weighted_sum]
            self.activations.append(activation)
        return self.activations[-1]

    def calculate_weighted_sum(self, inputs, weights, biases):
        weighted_sum = []
        for j in range(len(weights[0])):
            sum = 0
            for i in range(len(inputs)):
                sum += inputs[i] * weights[i][j]
            sum += biases[j]
            weighted_sum.append(sum)
        return weighted_sum

    def backward_propagate(self, targets, learning_rate):
        self.deltas = []
        for i in range(self.num_hidden_layers, -1, -1):
            if i == self.num_hidden_layers:
                error = [targets[j] - self.activations[i][j] for j in range(len(targets))]
                delta = [self.sigmoid_derivative(self.activations[i][j]) * error[j] for j in range(len(error))]
            else:
                error = [0 for _ in range(len(self.activations[i]))]
                for j in range(len(self.activations[i + 1])):
                    for k in range(len(self.activations[i])):
                        error[k] += self.deltas[-1][j] * self.weights[i + 1][k][j]
                delta = [self.relu_derivative(self.activations[i][j]) * error[j] for j in range(len(error))]
            self.deltas.append(delta)
        self.deltas.reverse()
        self.update_weights_and_biases(learning_rate)

    def update_weights_and_biases(self, learning_rate):
        for i in range(self.num_hidden_layers + 1):
            for j in range(len(self.weights[i])):
                for k in range(len(self.weights[i][0])):
                    if i == 0:
                        self.weights[i][j][k] += learning_rate * self.deltas[i][k] * self.outputs[i][j]
                    else:
                        self.weights[i][j][k] += learning_rate * self.deltas[i][k] * self.activations[i - 1][j]
            for j in range(len(self.biases[i])):
                self.biases[i][j] += learning_rate * self.deltas[i][j]

    def train(self, inputs, targets, learning_rate, num_iterations):
        for _ in range(num_iterations):
            self.forward_propagate(inputs)
            self.backward_propagate(targets, learning_rate)

    def predict(self, inputs):
        return self.forward_propagate(inputs)


