class NeuralNetwork:
    def __init__(self, input_dim, hidden_dim, output_dim, num_hidden_layers):
        self.input_dim = input_dim
        self.hidden_dim = hidden_dim
        self.output_dim = output_dim
        self.num_hidden_layers = num_hidden_layers
        self.weights = []
        self.biases = []

        for i in range(num_hidden_layers + 1):
            if i == 0:
                self.weights.append(np.random.rand(input_dim, hidden_dim))
                self.biases.append(np.zeros((1, hidden_dim)))
            elif i == num_hidden_layers:
                self.weights.append(np.random.rand(hidden_dim, output_dim))
                self.biases.append(np.zeros((1, output_dim)))
            else:
                self.weights.append(np.random.rand(hidden_dim, hidden_dim))
                self.biases.append(np.zeros((1, hidden_dim)))

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return np.maximum(x, 0)

    def relu_derivative(self, x):
        return np.where(x > 0, 1, 0)

    def forward_pass(self, inputs):
        outputs = []
        for i in range(self.num_hidden_layers + 1):
            if i == 0:
                output = np.dot(inputs, self.weights[i]) + self.biases[i]
                output = self.relu(output)
            elif i == self.num_hidden_layers:
                output = np.dot(outputs[-1], self.weights[i]) + self.biases[i]
                output = self.sigmoid(output)
            else:
                output = np.dot(outputs[-1], self.weights[i]) + self.biases[i]
                output = self.relu(output)
            outputs.append(output)
        return outputs

    def backward_pass(self, inputs, targets, outputs):
        errors = []
        for i in range(self.num_hidden_layers, -1, -1):
            if i == self.num_hidden_layers:
                error = targets - outputs[-1]
            else:
                error = np.dot(errors[-1], self.weights[i + 1].T)
            errors.append(error)
        return errors

    def update_weights(self, inputs, targets, outputs, errors):
        for i in range(self.num_hidden_layers + 1):
            if i == 0:
                dw = np.dot(inputs.T, errors[-i - 1])
                db = np.sum(errors[-i - 1], axis=0, keepdims=True)
            else:
                dw = np.dot(outputs[i - 1].T, errors[-i - 1])
                db = np.sum(errors[-i - 1], axis=0, keepdims=True)
            self.weights[i] += 0.1 * dw
            self.biases[i] += 0.1 * db

    def train(self, inputs, targets, num_iterations):
        for _ in range(num_iterations):
            outputs = self.forward_pass(inputs)
            errors = self.backward_pass(inputs, targets, outputs)
            self.update_weights(inputs, targets, outputs, errors)

    def predict(self, inputs):
        outputs = self.forward_pass(inputs)
        return outputs[-1]

