                error[i] = [(targets[k] - outputs[i+1][k]) * self.sigmoid_derivative(outputs[i+1][k]) for k in range(len(targets))]
            else:
                error[i] = [sum([error[i+1][k] * self.weights[i+1][j][k] for k in range(len(error[i+1]))]) * self.sigmoid_derivative(outputs[i+1][j]) for j in range(len(outputs[i+1]))]
            for j in range(len(self.weights[i])):
                for k in range(len(self.weights[i][j])):
                    self.weights[i][j][k] += learning_rate * error[i][j] * outputs[i][j]
            for k in range(len(self.biases[i])):
                self.biases[i][k] += learning_rate * error[i][k]

    def train(self, inputs, targets, learning_rate, epochs):
        for _ in range(epochs):
            for i in range(len(inputs)):
                self.backward_pass(inputs[i], targets[i], learning_rate)

    def predict(self, inputs):
        outputs = self.forward_pass(inputs)
        return outputs[-1]

