class NeuralNetwork:
    def __init__(self, learning_rate=0.1):
        self.learning_rate = learning_rate
        self.layers = []

    def add_layer(self, layer):
        self.layers.append(layer)

    def forward(self, inputs):
        outputs = inputs
        for layer in self.layers:
            outputs = layer.forward(outputs)
        return outputs

    def backward(self, inputs, targets):
        loss = self.calculate_loss(inputs, targets)
        d_outputs = self.calculate_d_outputs(inputs, targets)
        for layer in reversed(self.layers):
            d_outputs = layer.backward(d_outputs)

    def calculate_loss(self, inputs, targets):
        predictions = self.forward(inputs)
        return sum((t - p) ** 2 for t, p in zip(targets, predictions)) / len(targets)

    def calculate_d_outputs(self, inputs, targets):
        predictions = self.forward(inputs)
        return [2 * (t - p) for t, p in zip(targets, predictions)]


class Layer:
    def __init__(self, num_inputs, num_outputs):
        self.weights = [[0.1 for _ in range(num_outputs)] for _ in range(num_inputs)]
        self.bias = [0.1 for _ in range(num_outputs)]

    def forward(self, inputs):
        return [self.activation(self.calculate_output(i, inputs)) for i in range(len(self.bias))]

    def backward(self, d_outputs):
        d_weights = [[0 for _ in range(len(self.bias))] for _ in range(len(self.weights[0]))]
        d_bias = [0 for _ in range(len(self.bias))]
        for i in range(len(self.bias)):
            for j in range(len(self.weights[0])):
                d_weights[j][i] = d_outputs[i] * self.weights[j][i]
                d_bias[i] += d_outputs[i] * self.bias[i]
        self.weights = [[w + self.learning_rate * dw for w, dw in zip(ws, dws)] for ws, dws in zip(self.weights, d_weights)]
        self.bias = [b + self.learning_rate * db for b, db in zip(self.bias, d_bias)]
        return d_weights

    def calculate_output(self, i, inputs):
        return sum(w * x for w, x in zip(self.weights, inputs)) + self.bias[i]

    def activation(self, x):
        return 1 / (1 + exp(-x))


