import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_layers):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_layers = hidden_layers
        self.weights = []
        self.biases = []
        self.activations = []
        self.deltas = []
        self.init_network()

    def init_network(self):
        layers = [self.input_dim] + self.hidden_layers + [self.output_dim]
        for i in range(len(layers) - 1):
            self.weights.append(np.random.rand(layers[i], layers[i + 1]))
            self.biases.append(np.zeros((1, layers[i + 1])))
            self.activations.append(np.zeros((1, layers[i + 1])))
            self.deltas.append(np.zeros((1, layers[i + 1])))

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def forward_pass(self, inputs):
        self.activations[0] = inputs
        for i in range(len(self.weights)):
            self.activations[i + 1] = self.sigmoid(np.dot(self.activations[i], self.weights[i]) + self.biases[i])
        return self.activations[-1]

    def backward_pass(self, inputs, targets):
        self.forward_pass(inputs)
        self.deltas[-1] = (targets - self.activations[-1]) * self.sigmoid_derivative(self.activations[-1])
        for i in range(len(self.weights) - 1, 0, -1):
            self.deltas[i - 1] = np.dot(self.deltas[i], self.weights[i].T) * self.sigmoid_derivative(self.activations[i])

    def update_weights(self, inputs, targets, learning_rate):
        self.backward_pass(inputs, targets)
        for i in range(len(self.weights)):
            self.weights[i] += learning_rate * np.dot(self.activations[i].T, self.deltas[i])
            self.biases[i] += learning_rate * np.sum(self.deltas[i], axis=0, keepdims=True)

    def train(self, inputs, targets, learning_rate, epochs):
        for _ in range(epochs):
            for i in range(len(inputs)):
                self.update_weights(inputs[i], targets[i], learning_rate)

    def predict(self, inputs):
        return self.forward_pass(inputs)

