    def update_weights_and_biases(self, learning_rate):
        for i in range(len(self.weights)):
            for j in range(len(self.weights[i][0])):
                self.biases[i][j] += learning_rate * self.deltas[i + 1][j]
                for k in range(len(self.weights[i])):
                    self.weights[i][k][j] += learning_rate * self.deltas[i + 1][j] * self.outputs[i][k]

    def train(self, inputs, targets, learning_rate, epochs):
        for _ in range(epochs):
            self.forward_propagate(inputs)
            self.backward_propagate(targets)
            self.update_weights_and_biases(learning_rate)

