            else:
                self.outputs.append([self.sigmoid(x) for x in weighted_sum[0]])
        return self.outputs[-1]

    def backward_pass(self, inputs, targets, learning_rate):
        output_error = [target - output for target, output in zip(targets, self.outputs[-1])]
        output_delta = [output_error[i] * self.sigmoid_derivative(output) for i, output in enumerate(self.outputs[-1])]
