            hidden_delta = [hidden_error[k] * self.sigmoid_derivative(self.outputs[i][k]) for k in range(self.layers[i])]
            for k in range(self.layers[i]):
                for j in range(self.layers[i+1]):
                    self.weights[i][k][j] += learning_rate * hidden_delta[k] * self.outputs[i][k]
            self.biases[i] = [self.biases[i][j] + learning_rate * output_delta[j] for j in range(self.layers[i+1])]
            output_delta = hidden_delta
        for k in range(self.layers[0]):
