        self.biases[0] = [self.biases[0][j] + learning_rate * output_delta[j] for j in range(self.layers[1])]

    def train(self, inputs, targets, learning_rate, iterations):
        for _ in range(iterations):
            self.forward_pass(inputs)
            self.backward_pass(inputs, targets, learning_rate)

