    def __init__(self, input_size, output_size, hidden_sizes, activation='sigmoid'):
        self.input_size = input_size
        self.output_size = output_size
        self.hidden_sizes = hidden_sizes
        self.activation = activation
        self.weights = []
        self.biases = []

        # Initialize weights and biases
        sizes = [input_size] + hidden_sizes + [output_size]
        for i in range(len(sizes) - 1):
            self.weights.append(self.init_weights(sizes[i], sizes[i+1]))
            self.biases.append(self.init_bias(sizes[i+1]))

    def init_weights(self, rows, cols):
        return [[0.1 * (i + j) for j in range(cols)] for i in range(rows)]

    def init_bias(self, size):
        return [0.1 * i for i in range(size)]

    def sigmoid(self, x):
        return 1 / (1 + 2.71828 ** -x)

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def forward(self, inputs):
        outputs = inputs
        self.layer_outputs = [outputs]

        for i in range(len(self.weights)):
            weighted_sum = [sum([outputs[j] * self.weights[i][j][k] for j in range(len(outputs))]) + self.biases[i][k] for k in range(len(self.weights[i][0]))]
            if i < len(self.weights) - 1:
                if self.activation == 'sigmoid':
                    outputs = [self.sigmoid(x) for x in weighted_sum]
                else:
                    raise ValueError('Unsupported activation function')
            else:
                outputs = weighted_sum
            self.layer_outputs.append(outputs)

        return outputs

    def backward(self, inputs, targets, learning_rate):
        output_errors = [targets[i] - self.layer_outputs[-1][i] for i in range(len(targets))]

        for i in range(len(self.weights) - 1, -1, -1):
            if i < len(self.weights) - 1:
                output_errors = [sum([output_errors[k] * self.weights[i+1][j][k] for k in range(len(self.weights[i+1][0]))]) for j in range(len(self.weights[i+1]))]
                if self.activation == 'sigmoid':
                    output_errors = [x * self.sigmoid_derivative(y) for x, y in zip(output_errors, self.layer_outputs[i])]
                else:
                    raise ValueError('Unsupported activation function')

            for j in range(len(self.weights[i])):
                for k in range(len(self.weights[i][j])):
                    self.weights[i][j][k] += learning_rate * output_errors[j] * self.layer_outputs[i][j]
            for j in range(len(self.biases[i])):
                self.biases[i][j] += learning_rate * output_errors[j]

    def train(self, inputs, targets, iterations, learning_rate):
        for _ in range(iterations):
            self.forward(inputs)
            self.backward(inputs, targets, learning_rate)


