import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_layers):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_layers = hidden_layers
        self.weights = []
        self.biases = []
        self.activations = []
        self.initialize_network()

    def initialize_network(self):
        layers = [self.input_dim] + self.hidden_layers + [self.output_dim]
        for i in range(len(layers) - 1):
            self.weights.append(np.random.rand(layers[i], layers[i + 1]))
            self.biases.append(np.zeros((1, layers[i + 1])))
            if i < len(layers) - 2:
                self.activations.append('relu')
            else:
                self.activations.append('sigmoid')

    def forward_pass(self, inputs):
        outputs = [inputs]
        for i in range(len(self.weights)):
            weighted_sum = np.dot(outputs[-1], self.weights[i]) + self.biases[i]
            if self.activations[i] == 'relu':
                outputs.append(np.maximum(weighted_sum, 0))
            elif self.activations[i] == 'sigmoid':
                outputs.append(1 / (1 + np.exp(-weighted_sum)))
        return outputs

    def backward_pass(self, inputs, targets, learning_rate):
        outputs = self.forward_pass(inputs)
        errors = [targets - outputs[-1]]
        for i in range(len(self.weights) - 1, 0, -1):
            if self.activations[i] == 'relu':
                derivative = np.where(outputs[i] > 0, 1, 0)
            elif self.activations[i] == 'sigmoid':
                derivative = outputs[i] * (1 - outputs[i])
            error = np.dot(errors[-1], self.weights[i].T) * derivative
            errors.append(error)
        errors.reverse()
        for i in range(len(self.weights)):
            weight_update = np.dot(outputs[i].T, errors[i])
            bias_update = np.sum(errors[i], axis=0, keepdims=True)
            self.weights[i] += learning_rate * weight_update
            self.biases[i] += learning_rate * bias_update

    def train(self, inputs, targets, learning_rate, epochs):
        for _ in range(epochs):
            self.backward_pass(inputs, targets, learning_rate)

