class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_dims):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_dims = hidden_dims
        self.weights = []
        self.biases = []

        prev_dim = input_dim
        for dim in hidden_dims:
            self.weights.append([[0.1 for _ in range(prev_dim)] for _ in range(dim)])
            self.biases.append([0.1 for _ in range(dim)])
            prev_dim = dim
        self.weights.append([[0.1 for _ in range(prev_dim)] for _ in range(output_dim)])
        self.biases.append([0.1 for _ in range(output_dim)])

    def sigmoid(self, x):
        return 1 / (1 + 2.71828 ** -x)

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def forward_pass(self, inputs):
        activations = [inputs]
        for i in range(len(self.weights)):
            weights = self.weights[i]
            biases = self.biases[i]
            weighted_sum = [[sum([inputs[j] * weights[k][j] for j in range(len(inputs))]) + biases[k] for k in range(len(weights))]]
            weighted_sum = weighted_sum[0]
            if i < len(self.weights) - 1:
                activation = [self.sigmoid(x) for x in weighted_sum]
            else:
                activation = [self.sigmoid(x) for x in weighted_sum]
            inputs = activation
            activations.append(activation)
        return activations

    def backpropagate(self, inputs, targets, learning_rate):
        activations = self.forward_pass(inputs)
        output_error = [targets[i] - activations[-1][i] for i in range(len(targets))]
        for i in reversed(range(len(self.weights))):
            if i == len(self.weights) - 1:
                deltas = [output_error[j] * self.sigmoid_derivative(activations[-1][j]) for j in range(len(output_error))]
            else:
                weights = self.weights[i + 1]
                deltas_next = deltas
                deltas = [sum([deltas_next[j] * weights[j][k] for j in range(len(deltas_next))]) * self.sigmoid_derivative(activations[i + 1][k]) for k in range(len(activations[i + 1]))]
            if i > 0:
                weights_update = [[learning_rate * deltas[j] * activations[i][k] for k in range(len(activations[i]))] for j in range(len(deltas))]
                biases_update = [learning_rate * deltas[j] for j in range(len(deltas))]
            else:
                weights_update = [[learning_rate * deltas[j] * inputs[k] for k in range(len(inputs))] for j in range(len(deltas))]
                biases_update = [learning_rate * deltas[j] for j in range(len(deltas))]
            self.weights[i] = [[self.weights[i][j][k] + weights_update[j][k] for k in range(len(self.weights[i][j]))] for j in range(len(self.weights[i]))]
            self.biases[i] = [self.biases[i][j] + biases_update[j] for j in range(len(self.biases[i]))]
        return activations[-1]

