import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_layers):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_layers = hidden_layers
        self.weights = []
        self.biases = []

        for i in range(len(hidden_layers) + 1):
            if i == 0:
                self.weights.append(np.random.rand(input_dim, hidden_layers[i]))
                self.biases.append(np.zeros((1, hidden_layers[i])))
            elif i == len(hidden_layers):
                self.weights.append(np.random.rand(hidden_layers[i-1], output_dim))
                self.biases.append(np.zeros((1, output_dim)))
            else:
                self.weights.append(np.random.rand(hidden_layers[i-1], hidden_layers[i]))
                self.biases.append(np.zeros((1, hidden_layers[i])))

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def forward_propagate(self, inputs):
        outputs = []
        for i in range(len(self.weights)):
            if i == 0:
                output = self.sigmoid(np.dot(inputs, self.weights[i]) + self.biases[i])
            else:
                output = self.sigmoid(np.dot(outputs[-1], self.weights[i]) + self.biases[i])
            outputs.append(output)
        return outputs

    def backward_propagate(self, inputs, targets, outputs):
        errors = []
        for i in range(len(self.weights) - 1, -1, -1):
            if i == len(self.weights) - 1:
                error = targets - outputs[-1]
            else:
                error = np.dot(errors[-1], self.weights[i+1].T) * self.sigmoid_derivative(outputs[i])
            errors.append(error)
        return errors

    def update_weights(self, inputs, errors, outputs):
        for i in range(len(self.weights)):
            if i == 0:
                self.weights[i] += np.dot(inputs.T, errors[-i-1])
                self.biases[i] += np.sum(errors[-i-1], axis=0, keepdims=True)
            else:
                self.weights[i] += np.dot(outputs[i-1].T, errors[-i-1])
                self.biases[i] += np.sum(errors[-i-1], axis=0, keepdims=True)

    def train(self, inputs, targets, epochs):
        for _ in range(epochs):
            outputs = self.forward_propagate(inputs)
            errors = self.backward_propagate(inputs, targets, outputs)
            self.update_weights(inputs, errors, outputs)

    def predict(self, inputs):
        outputs = self.forward_propagate(inputs)
        return outputs[-1]

