class NeuralNetwork:
    def __init__(self, input_dim, hidden_dim, output_dim):
        self.input_dim = input_dim
        self.hidden_dim = hidden_dim
        self.output_dim = output_dim
        self.weights1 = [[random.random() for _ in range(input_dim)] for _ in range(hidden_dim)]
        self.weights2 = [[random.random() for _ in range(hidden_dim)] for _ in range(output_dim)]
        self.bias1 = [random.random() for _ in range(hidden_dim)]
        self.bias2 = [random.random() for _ in range(output_dim)]

    def sigmoid(self, x):
        return 1 / (1 + math.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def forward_propagate(self, inputs):
        hidden_layer = [self.sigmoid(sum([inputs[i] * self.weights1[j][i] for i in range(self.input_dim)]) + self.bias1[j]) for j in range(self.hidden_dim)]
        outputs = [self.sigmoid(sum([hidden_layer[i] * self.weights2[j][i] for i in range(self.hidden_dim)]) + self.bias2[j]) for j in range(self.output_dim)]
        return hidden_layer, outputs

    def backward_propagate(self, inputs, targets, hidden_layer, outputs):
        output_errors = [targets[i] - outputs[i] for i in range(self.output_dim)]
        output_deltas = [output_errors[i] * self.sigmoid_derivative(outputs[i]) for i in range(self.output_dim)]
        hidden_errors = [sum([output_deltas[i] * self.weights2[i][j] for i in range(self.output_dim)]) for j in range(self.hidden_dim)]
        hidden_deltas = [hidden_errors[i] * self.sigmoid_derivative(hidden_layer[i]) for i in range(self.hidden_dim)]
        return output_deltas, hidden_deltas

    def update_weights(self, inputs, hidden_layer, output_deltas, hidden_deltas):
        for i in range(self.hidden_dim):
            for j in range(self.input_dim):
                self.weights1[i][j] += 0.1 * inputs[j] * hidden_deltas[i]
        for i in range(self.output_dim):
            for j in range(self.hidden_dim):
                self.weights2[i][j] += 0.1 * hidden_layer[j] * output_deltas[i]
        for i in range(self.hidden_dim):
            self.bias1[i] += 0.1 * hidden_deltas[i]
        for i in range(self.output_dim):
            self.bias2[i] += 0.1 * output_deltas[i]

    def train(self, inputs, targets):
        hidden_layer, outputs = self.forward_propagate(inputs)
        output_deltas, hidden_deltas = self.backward_propagate(inputs, targets, hidden_layer, outputs)
        self.update_weights(inputs, hidden_layer, output_deltas, hidden_deltas)

    def predict(self, inputs):
        hidden_layer, outputs = self.forward_propagate(inputs)
        return outputs

