            if i < len(self.weights) - 1:
                error *= self.relu_derivative(outputs[i])
            else:
                error *= self.sigmoid_derivative(outputs[i])

            errors.append(error)

        return errors[::-1]

    def update_weights(self, inputs, errors, outputs):
        for i in range(len(self.weights)):
            if i == 0:
                self.weights[i] += np.dot(inputs.T, errors[i])
            else:
                self.weights[i] += np.dot(outputs[i-1].T, errors[i])

            self.biases[i] += np.sum(errors[i], axis=0, keepdims=True)

    def train(self, inputs, targets, epochs, learning_rate):
        for epoch in range(epochs):
            outputs = self.forward_pass(inputs)
            errors = self.backward_pass(inputs, targets, outputs)
            self.update_weights(inputs, errors, outputs)

            for i in range(len(self.weights)):
                self.weights[i] *= learning_rate
                self.biases[i] *= learning_rate

            print(f'Epoch {epoch+1}, Loss: {np.mean(np.square(targets - outputs[-1]))}')

    def predict(self, inputs):
        outputs = self.forward_pass(inputs)
        return outputs[-1]

