        self.init_weights_and_biases()

    def init_weights_and_biases(self):
        num_layers = len(self.hidden_layers) + 1
        for i in range(num_layers):
            if i == 0:
                weight = [[0.0 for _ in range(self.hidden_layers[i])] for _ in range(self.input_dim)]
                bias = [0.0 for _ in range(self.hidden_layers[i])]
            elif i == num_layers - 1:
                weight = [[0.0 for _ in range(self.output_dim)] for _ in range(self.hidden_layers[i-1])]
                bias = [0.0 for _ in range(self.output_dim)]
            else:
                weight = [[0.0 for _ in range(self.hidden_layers[i])] for _ in range(self.hidden_layers[i-1])]
                bias = [0.0 for _ in range(self.hidden_layers[i])]
            self.weights.append(weight)
            self.biases.append(bias)
            self.activations.append([0.0 for _ in range(len(bias))])
            self.deltas.append([0.0 for _ in range(len(bias))])
            self.z_values.append([0.0 for _ in range(len(bias))])

    def sigmoid(self, x):
        return 1 / (1 + 2.71828**(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def tanh(self, x):
        return 2 / (1 + 2.71828**(-2*x)) - 1

    def tanh_derivative(self, x):
        return 1 - x**2

    def relu(self, x):
        return max(0, x)

    def relu_derivative(self, x):
        return 1 if x > 0 else 0

    def forward_pass(self, inputs):
        self.activations[0] = inputs
        for i in range(len(self.hidden_layers) + 1):
            if i == 0:
                for j in range(self.hidden_layers[i]):
                    self.z_values[i][j] = sum([inputs[k] * self.weights[i][k][j] for k in range(self.input_dim)]) + self.biases[i][j]
                    self.activations[i+1][j] = self.sigmoid(self.z_values[i][j])
            elif i == len(self.hidden_layers):
                for j in range(self.output_dim):
                    self.z_values[i][j] = sum([self.activations[i][k] * self.weights[i][k][j] for k in range(self.hidden_layers[i-1])]) + self.biases[i][j]
                    self.activations[i+1][j] = self.sigmoid(self.z_values[i][j])
            else:
                for j in range(self.hidden_layers[i]):
                    self.z_values[i][j] = sum([self.activations[i][k] * self.weights[i][k][j] for k in range(self.hidden_layers[i-1])]) + self.biases[i][j]
                    self.activations[i+1][j] = self.sigmoid(self.z_values[i][j])
        return self.activations[-1]

    def backward_pass(self, targets, learning_rate):
        output_error = [0.0 for _ in range(self.output_dim)]
        for i in range(self.output_dim):
            output_error[i] = targets[i] - self.activations[-1][i]
            self.deltas[-1][i] = output_error[i] * self.sigmoid_derivative(self.activations[-1][i])
        for i in range(len(self.hidden_layers) - 1, -1, -1):
            for j in range(self.hidden_layers[i]):
                error = sum([self.deltas[i+1][k] * self.weights[i+1][j][k] for k in range(len(self.deltas[i+1]))])
                self.deltas[i][j] = error * self.sigmoid_derivative(self.activations[i+1][j])
        for i in range(len(self.hidden_layers) + 1):
            if i == 0:
                for j in range(self.hidden_layers[i]):
                    for k in range(self.input_dim):
                        self.weights[i][k][j] += learning_rate * self.deltas[i+1][j] * self.activations[i][k]
                    self.biases[i][j] += learning_rate * self.deltas[i+1][j]
            elif i == len(self.hidden_layers):
                for j in range(self.output_dim):
                    for k in range(self.hidden_layers[i-1]):
                        self.weights[i][k][j] += learning_rate * self.deltas[i+1][j] * self.activations[i][k]
                    self.biases[i][j] += learning_rate * self.deltas[i+1][j]
            else:
                for j in range(self.hidden_layers[i]):
