        self.input_dim = input_dim
        self.hidden_dim = hidden_dim
        self.output_dim = output_dim
        self.num_hidden_layers = num_hidden_layers
        self.weights = []
        self.biases = []
        self.init_weights_and_biases()

    def init_weights_and_biases(self):
        for i in range(self.num_hidden_layers + 1):
            if i == 0:
                self.weights.append([[0.1 for _ in range(self.input_dim)] for _ in range(self.hidden_dim)])
                self.biases.append([0.1 for _ in range(self.hidden_dim)])
            elif i == self.num_hidden_layers:
                self.weights.append([[0.1 for _ in range(self.hidden_dim)] for _ in range(self.output_dim)])
                self.biases.append([0.1 for _ in range(self.output_dim)])
            else:
                self.weights.append([[0.1 for _ in range(self.hidden_dim)] for _ in range(self.hidden_dim)])
                self.biases.append([0.1 for _ in range(self.hidden_dim)])

    def sigmoid(self, x):
        return 1 / (1 + 2.71828 ** -x)

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return max(0, x)

    def relu_derivative(self, x):
        return 1 if x > 0 else 0

    def forward_pass(self, inputs):
        outputs = []
        for i in range(self.num_hidden_layers + 1):
            if i == 0:
                weighted_sum = [sum([inputs[j] * self.weights[i][k][j] for j in range(self.input_dim)]) + self.biases[i][k] for k in range(self.hidden_dim)]
                outputs.append([self.sigmoid(x) for x in weighted_sum])
            elif i == self.num_hidden_layers:
                weighted_sum = [sum([outputs[-1][j] * self.weights[i][k][j] for j in range(self.hidden_dim)]) + self.biases[i][k] for k in range(self.output_dim)]
                outputs.append([self.sigmoid(x) for x in weighted_sum])
            else:
                weighted_sum = [sum([outputs[-1][j] * self.weights[i][k][j] for j in range(self.hidden_dim)]) + self.biases[i][k] for k in range(self.hidden_dim)]
                outputs.append([self.sigmoid(x) for x in weighted_sum])
        return outputs

    def backpropagate(self, inputs, targets, learning_rate):
        outputs = self.forward_pass(inputs)
        output_error = [targets[i] - outputs[-1][i] for i in range(self.output_dim)]
        output_delta = [output_error[i] * self.sigmoid_derivative(outputs[-1][i]) for i in range(self.output_dim)]
        for i in range(self.num_hidden_layers - 1, -1, -1):
            if i == self.num_hidden_layers - 1:
                hidden_error = [sum([output_delta[j] * self.weights[-1][j][k] for j in range(self.output_dim)]) for k in range(self.hidden_dim)]
                hidden_delta = [hidden_error[k] * self.sigmoid_derivative(outputs[i][k]) for k in range(self.hidden_dim)]
            else:
                hidden_error = [sum([hidden_delta[j] * self.weights[i + 1][j][k] for j in range(self.hidden_dim)]) for k in range(self.hidden_dim)]
                hidden_delta = [hidden_error[k] * self.sigmoid_derivative(outputs[i][k]) for k in range(self.hidden_dim)]
            for j in range(self.hidden_dim):
                for k in range(self.hidden_dim):
                    self.weights[i][j][k] += learning_rate * hidden_delta[j] * outputs[i - 1][k] if i > 0 else learning_rate * hidden_delta[j] * inputs[k]
            for j in range(self.hidden_dim):
                self.biases[i][j] += learning_rate * hidden_delta[j]
        for i in range(self.output_dim):
            for j in range(self.hidden_dim):
                self.weights[-1][i][j] += learning_rate * output_delta[i] * outputs[-2][j]
            self.biases[-1][i] += learning_rate * output_delta[i]

    def train(self, inputs, targets, learning_rate, num_iterations):
        for _ in range(num_iterations):
            self.backpropagate(inputs, targets, learning_rate)

    def predict(self, inputs):
        outputs = self.forward_pass(inputs)
        return outputs[-1]

