class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_dim, num_hidden):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_dim = hidden_dim
        self.num_hidden = num_hidden
        self.weights = []
        self.biases = []
        self.initialize_weights()

    def initialize_weights(self):
        for i in range(self.num_hidden + 1):
            if i == 0:
                weight = np.random.rand(self.input_dim, self.hidden_dim)
            elif i == self.num_hidden:
                weight = np.random.rand(self.hidden_dim, self.output_dim)
            else:
                weight = np.random.rand(self.hidden_dim, self.hidden_dim)
            bias = np.zeros((1, weight.shape[1]))
            self.weights.append(weight)
            self.biases.append(bias)

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def forward_pass(self, inputs):
        outputs = []
        for i in range(self.num_hidden + 1):
            if i == 0:
                output = np.dot(inputs, self.weights[i]) + self.biases[i]
            else:
                output = np.dot(outputs[-1], self.weights[i]) + self.biases[i]
            if i < self.num_hidden:
                output = self.sigmoid(output)
            else:
                output = self.sigmoid(output)
            outputs.append(output)
        return outputs

    def backward_pass(self, inputs, targets, outputs):
        errors = []
        for i in range(self.num_hidden + 1):
            if i == self.num_hidden:
                error = targets - outputs[-1]
            else:
                error = np.dot(errors[-1], self.weights[self.num_hidden - i].T)
            errors.append(error)
        errors.reverse()
        weight_updates = []
        bias_updates = []
        for i in range(self.num_hidden + 1):
            if i == 0:
                weight_update = np.dot(inputs.T, errors[i] * self.sigmoid_derivative(outputs[i]))
            else:
                weight_update = np.dot(outputs[i - 1].T, errors[i] * self.sigmoid_derivative(outputs[i]))
            bias_update = np.sum(errors[i] * self.sigmoid_derivative(outputs[i]), axis=0, keepdims=True)
            weight_updates.append(weight_update)
            bias_updates.append(bias_update)
        return weight_updates, bias_updates

    def train(self, inputs, targets, learning_rate, epochs):
        for _ in range(epochs):
            outputs = self.forward_pass(inputs)
            weight_updates, bias_updates = self.backward_pass(inputs, targets, outputs)
            for i in range(self.num_hidden + 1):
                self.weights[i] += learning_rate * weight_updates[i]
                self.biases[i] += learning_rate * bias_updates[i]

    def predict(self, inputs):
        outputs = self.forward_pass(inputs)
        return outputs[-1]

