import numpy as np

class NeuralNetwork:
    def __init__(self, input_dim, hidden_dim, output_dim, activation='sigmoid', lr=0.01):
        self.input_dim = input_dim
        self.hidden_dim = hidden_dim
        self.output_dim = output_dim
        self.activation = activation
        self.lr = lr
        self.weights1 = np.random.rand(input_dim, hidden_dim)
        self.weights2 = np.random.rand(hidden_dim, output_dim)
        self.bias1 = np.zeros((1, hidden_dim))
        self.bias2 = np.zeros((1, output_dim))

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return np.maximum(x, 0)

    def relu_derivative(self, x):
        return np.where(x > 0, 1, 0)

    def forward(self, inputs):
        self.hidden_layer = np.dot(inputs, self.weights1) + self.bias1
        if self.activation == 'sigmoid':
            self.hidden_layer = self.sigmoid(self.hidden_layer)
        elif self.activation == 'relu':
            self.hidden_layer = self.relu(self.hidden_layer)
        self.output_layer = np.dot(self.hidden_layer, self.weights2) + self.bias2
        return self.output_layer

    def backward(self, inputs, targets, outputs):
        output_error = targets - outputs
        output_delta = output_error * 1
        self.weights2 += self.lr * np.dot(self.hidden_layer.T, output_delta)
        self.bias2 += self.lr * np.sum(output_delta, axis=0, keepdims=True)
        hidden_error = np.dot(output_delta, self.weights2.T)
        if self.activation == 'sigmoid':
            hidden_delta = hidden_error * self.sigmoid_derivative(self.hidden_layer)
