        for i in range(len(layers) - 1):
            self.weights.append([[0.1 for _ in range(layers[i+1])] for _ in range(layers[i])])
            self.biases.append([0.1 for _ in range(layers[i+1])])

    def sigmoid(self, x):
        return 1 / (1 + 2.71828**(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def forward_pass(self, inputs):
        outputs = [inputs]
        for i in range(len(self.weights)):
            weighted_sum = [[sum([outputs[i][k] * self.weights[i][k][j] for k in range(len(outputs[i]))]) + self.biases[i][j] for j in range(len(self.weights[i][0]))] for _ in range(len(inputs))]
            if self.activation == 'sigmoid':
                output = [[self.sigmoid(weighted_sum[m][n]) for n in range(len(weighted_sum[0]))] for m in range(len(weighted_sum))]
            outputs.append(output)
        return outputs

    def backward_pass(self, inputs, targets, outputs):
        errors = []
        for i in range(len(outputs) - 1, 0, -1):
            if i == len(outputs) - 1:
                error = [[targets[m][n] - outputs[i][m][n] for n in range(len(outputs[i][0]))] for m in range(len(outputs[i]))]
            else:
