            errors.append(error)
        errors.reverse()
        weight_updates = []
        bias_updates = []
        for i in range(len(self.weights)):
            weight_update = [[0 for _ in range(len(self.weights[i][0]))] for _ in range(len(self.weights[i]))]
            bias_update = [0 for _ in range(len(self.biases[i]))]
            for j in range(len(outputs[i])):
                for k in range(len(self.weights[i][0])):
                    weight_update[j][k] += errors[i][j][k] * outputs[i][j]
                    bias_update[k] += errors[i][j][k]
            weight_updates.append(weight_update)
            bias_updates.append(bias_update)
        return weight_updates, bias_updates

    def train(self, inputs, targets, learning_rate, num_iterations):
        for _ in range(num_iterations):
            outputs = self.forward_pass(inputs)
            weight_updates, bias_updates = self.backward_pass(inputs, targets, outputs)
            for i in range(len(self.weights)):
                for j in range(len(self.weights[i])):
                    for k in range(len(self.weights[i][0])):
                        self.weights[i][j][k] += learning_rate * weight_updates[i][j][k]
                for j in range(len(self.biases[i])):
