import numpy as np

class Layer:
    def __init__(self, input_size, output_size):
        self.weights = np.random.rand(input_size, output_size)
        self.bias = np.zeros((1, output_size))

    def forward(self, input_data):
        return np.dot(input_data, self.weights) + self.bias

    def backward(self, input_data, output_error):
        weights_error = np.dot(input_data.T, output_error)
        bias_error = np.sum(output_error, axis=0, keepdims=True)
        return weights_error, bias_error

class ActivationLayer:
    def __init__(self, activation_function):
        self.activation_function = activation_function

    def forward(self, input_data):
        return self.activation_function(input_data)

    def backward(self, input_data, output_error):
        return output_error * self.activation_function_derivative(input_data)

    def activation_function_derivative(self, input_data):
        if self.activation_function == np.tanh:
            return 1 - np.tanh(input_data) ** 2
        elif self.activation_function == np.sigmoid:
            return self.activation_function(input_data) * (1 - self.activation_function(input_data))
        elif self.activation_function == np.relu:
            return np.where(input_data > 0, 1, 0)
        else:
            raise ValueError("Invalid activation function")

class NeuralNetwork:
    def __init__(self, input_size, output_size, hidden_layers, activation_functions):
        self.layers = []
        self.layers.append(Layer(input_size, hidden_layers[0]))
        for i in range(len(hidden_layers) - 1):
            self.layers.append(ActivationLayer(activation_functions[i]))
            self.layers.append(Layer(hidden_layers[i], hidden_layers[i + 1]))
        self.layers.append(ActivationLayer(activation_functions[-1]))
        self.layers.append(Layer(hidden_layers[-1], output_size))

    def forward(self, input_data):
        output = input_data
        for layer in self.layers:
            output = layer.forward(output)
        return output

    def backward(self, input_data, output_error):
        errors = []
        for i in range(len(self.layers) - 1, -1, -1):
            if isinstance(self.layers[i], Layer):
                weights_error, bias_error = self.layers[i].backward(input_data, output_error)
                errors.append((weights_error, bias_error))
                output_error = np.dot(output_error, self.layers[i].weights.T)
            else:
                output_error = self.layers[i].backward(input_data, output_error)
                errors.append(output_error)
        return errors

    def train(self, input_data, output_data, learning_rate, epochs):
        for _ in range(epochs):
            output = self.forward(input_data)
            output_error = output - output_data
            errors = self.backward(input_data, output_error)
            for i in range(len(self.layers)):
                if isinstance(self.layers[i], Layer):
                    weights_error, bias_error = errors[len(self.layers) - i - 1]
                    self.layers[i].weights -= learning_rate * weights_error
                    self.layers[i].bias -= learning_rate * bias_error

