import numpy as np

class Layer:
    def __init__(self, input_dim, output_dim):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.weights = np.random.randn(input_dim, output_dim)
        self.bias = np.zeros((1, output_dim))

    def forward(self, inputs):
        self.inputs = inputs
        return np.dot(inputs, self.weights) + self.bias

    def backward(self, error):
        weights_error = np.dot(self.inputs.T, error)
        inputs_error = np.dot(error, self.weights.T)
        bias_error = np.sum(error, axis=0, keepdims=True)
        return inputs_error, weights_error, bias_error

class Activation:
    def __init__(self, activation_type):
        self.activation_type = activation_type

    def forward(self, inputs):
        if self.activation_type == 'sigmoid':
            return 1 / (1 + np.exp(-inputs))
        elif self.activation_type == 'relu':
            return np.maximum(inputs, 0)
        else:
            raise ValueError('Invalid activation type')

    def backward(self, error):
        if self.activation_type == 'sigmoid':
            return error * (1 - np.multiply(self.forward(self.inputs), self.forward(self.inputs)))
        elif self.activation_type == 'relu':
            return error * (self.inputs > 0)

class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_dim, hidden_layers, activation_type):
        self.layers = []
        self.layers.append(Layer(input_dim, hidden_dim))
        self.layers.append(Activation(activation_type))
        for _ in range(hidden_layers - 1):
            self.layers.append(Layer(hidden_dim, hidden_dim))
            self.layers.append(Activation(activation_type))
        self.layers.append(Layer(hidden_dim, output_dim))
        self.layers.append(Activation(activation_type))

    def forward(self, inputs):
        outputs = inputs
        for layer in self.layers:
            outputs = layer.forward(outputs)
        return outputs

    def backward(self, error):
        errors = [error]
        for layer in reversed(self.layers):
            if isinstance(layer, Layer):
                error, weights_error, bias_error = layer.backward(errors[-1])
                layer.weights -= 0.1 * weights_error
                layer.bias -= 0.1 * bias_error
            elif isinstance(layer, Activation):
                error = layer.backward(errors[-1])
            errors.append(error)
        return errors[-1]

    def train(self, inputs, targets, epochs):
        for _ in range(epochs):
            outputs = self.forward(inputs)
            error = targets - outputs
            self.backward(error)

    def predict(self, inputs):
        return self.forward(inputs)

