import numpy as np

class Layer:
    def __init__(self, inputs, outputs):
        self.weights = np.random.rand(inputs, outputs)
        self.bias = np.zeros((1, outputs))

    def forward(self, inputs):
        self.inputs = inputs
        return np.dot(inputs, self.weights) + self.bias

    def backward(self, error):
        weights_error = np.dot(self.inputs.T, error)
        bias_error = np.sum(error, axis=0, keepdims=True)
        return np.dot(error, self.weights.T), weights_error, bias_error


class Activation:
    def __init__(self, activation_type):
        self.activation_type = activation_type

    def forward(self, inputs):
        if self.activation_type == 'sigmoid':
            return 1 / (1 + np.exp(-inputs))
        elif self.activation_type == 'relu':
            return np.maximum(inputs, 0)
        elif self.activation_type == 'tanh':
            return np.tanh(inputs)

    def backward(self, error):
        if self.activation_type == 'sigmoid':
            return error * self.forward(error) * (1 - self.forward(error))
        elif self.activation_type == 'relu':
            return error * (self.forward(error) > 0)
        elif self.activation_type == 'tanh':
            return error * (1 - self.forward(error) ** 2)


class NeuralNetwork:
    def __init__(self, input_size, output_size):
        self.layers = []
        self.input_size = input_size
        self.output_size = output_size

    def add_layer(self, size, activation_type):
        if not self.layers:
            self.layers.append(Layer(self.input_size, size))
        else:
            self.layers.append(Layer(self.layers[-1].weights.shape[1], size))
        self.layers.append(Activation(activation_type))

    def forward(self, inputs):
        outputs = inputs
        for layer in self.layers:
            outputs = layer.forward(outputs)
        return outputs

    def backward(self, error):
        errors = []
        for layer in reversed(self.layers):
            error, weights_error, bias_error = layer.backward(error)
            errors.append((weights_error, bias_error))
        return list(reversed(errors))

    def train(self, inputs, targets, learning_rate, epochs):
        for _ in range(epochs):
            outputs = self.forward(inputs)
            error = targets - outputs
            errors = self.backward(error)
            for i, layer in enumerate(self.layers):
                if isinstance(layer, Layer):
                    layer.weights += learning_rate * errors[i][0]
                    layer.bias += learning_rate * errors[i][1]


