class NeuralNetwork:
    def __init__(self, input_dim, output_dim, hidden_layers):
        self.input_dim = input_dim
        self.output_dim = output_dim
        self.hidden_layers = hidden_layers
        self.weights = []
        self.biases = []
        self.initialize_weights_and_biases()

    def initialize_weights_and_biases(self):
        layers = [self.input_dim] + self.hidden_layers + [self.output_dim]
        for i in range(len(layers) - 1):
            self.weights.append([[0.1 * (2 * j + 1) for j in range(layers[i + 1])] for _ in range(layers[i])])
            self.biases.append([0.1 * (2 * j + 1) for j in range(layers[i + 1])])

    def sigmoid(self, x):
        return 1 / (1 + 2.71828 ** -x)

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def forward_propagate(self, inputs):
        outputs = [inputs]
        for i in range(len(self.weights)):
            weighted_sum = [[sum([outputs[-1][j] * self.weights[i][j][k] for j in range(len(outputs[-1]))]) + self.biases[i][k] for k in range(len(self.biases[i]))]]
            outputs.append([self.sigmoid(x) for x in weighted_sum[0]])
        return outputs

    def backward_propagate(self, inputs, targets, learning_rate):
        outputs = self.forward_propagate(inputs)
        error = [0] * len(self.weights)
        for i in range(len(self.weights) - 1, -1, -1):
            if i == len(self.weights) - 1:
                error[i] = [2 * (outputs[-1][j] - targets[j]) * self.sigmoid_derivative(outputs[-1][j]) for j in range(len(outputs[-1]))]
            else:
                error[i] = [sum([error[i + 1][k] * self.weights[i + 1][j][k] for k in range(len(self.weights[i + 1]))]) * self.sigmoid_derivative(outputs[i + 1][j]) for j in range(len(outputs[i + 1]))]
            for j in range(len(self.weights[i])):
                for k in range(len(self.weights[i][j])):
                    self.weights[i][j][k] -= learning_rate * error[i][j] * outputs[i][j]
            for j in range(len(self.biases[i])):
                self.biases[i][j] -= learning_rate * error[i][j]

    def train(self, inputs, targets, learning_rate, epochs):
        for _ in range(epochs):
            for i in range(len(inputs)):
                self.backward_propagate(inputs[i], targets[i], learning_rate)

    def predict(self, inputs):
        return self.forward_propagate(inputs)[-1]

# Example usage
